def faq_schema(page):
    parts = []
    for q, a in page['faq']:
        parts.append('{"@type":"Question","name":"%s","acceptedAnswer":{"@type":"Answer","text":"%s"}}' % (escape(q), escape(a)))
    return '[' + ','.join(parts) + ']'


def related_links_html(page):
    items = ''.join(f'<li><a href="{href}">{label}</a></li>' for label, href in page['related'])
    return f'<ul>{items}</ul>'


def area_list_html():
    return ''.join(f'<li>{escape(area)}</li>' for area in AREAS)


